const NotFoundPage = () => {
  return (
    <section className="card">
      <div className="page-header">
        <h2>Page not found</h2>
        <p className="muted">
          The page you requested does not exist. Use the sidebar to navigate.
        </p>
      </div>
    </section>
  );
};

export default NotFoundPage;
